## Test Cases

```typescript
describe('thinking blocks', () => {
  let toolState: ToolState;

  beforeEach(() => {
    toolState = createToolState();
  });

  it('sets inThinking on content_block_start with thinking type', async () => {
    const events = await collectEvents(
      {
        type: 'stream_event',
        event: {
          type: 'content_block_start',
          content_block: { type: 'thinking' },
        },
      },
      mockSession,
      'test-session',
      toolState
    );

    expect(events).toHaveLength(0); // No event emitted on start
    expect(toolState.inThinking).toBe(true);
    expect(toolState.thinkingStartMs).toBeGreaterThan(0);
  });

  it('yields thinking_delta when inThinking is true', async () => {
    toolState.inThinking = true;
    toolState.thinkingStartMs = Date.now();

    const events = await collectEvents(
      {
        type: 'stream_event',
        event: {
          type: 'content_block_delta',
          delta: { type: 'thinking_delta', thinking: 'Let me reason about this' },
        },
      },
      mockSession,
      'test-session',
      toolState
    );

    expect(events).toEqual([
      {
        type: 'thinking_delta',
        data: { text: 'Let me reason about this' },
      },
    ]);
  });

  it('ignores thinking_delta when inThinking is false', async () => {
    // inThinking defaults to false
    const events = await collectEvents(
      {
        type: 'stream_event',
        event: {
          type: 'content_block_delta',
          delta: { type: 'thinking_delta', thinking: 'stale thinking' },
        },
      },
      mockSession,
      'test-session',
      toolState
    );

    expect(events).toHaveLength(0);
  });

  it('resets inThinking on content_block_stop during thinking', async () => {
    toolState.inThinking = true;

    const events = await collectEvents(
      {
        type: 'stream_event',
        event: { type: 'content_block_stop' },
      },
      mockSession,
      'test-session',
      toolState
    );

    expect(events).toHaveLength(0); // No event emitted on stop
    expect(toolState.inThinking).toBe(false);
  });

  it('handles thinking → text transition correctly', async () => {
    // Start thinking
    await collectEvents(
      {
